sed -n '1,220p' predict.py && python - <<'PY'
import torch, os
ck1='checkpoints/iter15_b5_26ep.pt'
ck2='checkpoints/iter18_b5_34ep.pt'
out='checkpoints/avg26_34_a025.pt'
a=0.25
c1=torch.load(ck1,map_location='cpu')
c2=torch.load(ck2,map_location='cpu')
s1=c1.get('model', c1.get('state_dict'))
s2=c2.get('model', c2.get('state_dict'))
avg={}
for k,v in s1.items():
    if k in s2 and torch.is_tensor(v) and torch.is_tensor(s2[k]) and v.shape==s2[k].shape and v.is_floating_point():
        avg[k]=v*(1-a)+s2[k]*a
    else:
        avg[k]=v
ck=dict(c1)
if 'model' in ck:
    ck['model']=avg
elif 'state_dict' in ck:
    ck['state_dict']=avg
else:
    ck={'model':avg}
ck['epoch']='interp_26_34_a025'
ck['args']={'source_a':ck1,'source_b':ck2,'alpha_to_b':a,'note':'weighted interpolation'}
os.makedirs('checkpoints',exist_ok=True)
torch.save(ck,out)
print('saved',out)
PY
